#include <cstring>

void safe_copy(char* dst, const char* src, std::size_t dst_size) {
    if (dst_size == 0) return;
    std::strncpy(dst, src, dst_size - 1);
    dst[dst_size - 1] = '\0';
}

int main() {
    char buf[10];
    safe_copy(buf, "Testing", 10);
    return buf[0] == 'T' ? 1 : 0;
}

