#include <cstring>
#include <clocale>

int main() {
    std::setlocale(LC_COLLATE, "");
    const char* a = "ä";
    const char* b = "z";
    // strcmp تقارن بـ ASCII: ä (228) > z (122)
    // strcoll قد تعتبر ä قبل z حسب اللغة الألمانية
    int cmp = std::strcoll(a, b);
    return cmp != std::strcmp(a, b) ? 1 : 0; // قد تختلف
}

#include <cstring>

int main() {
    // strcmp دائمًا بالبايتات — سريع ومحدد
    // strcoll باللغة المحلية — أبطأ لكن أدق للعرض
    const char* words[] = {"cafe", "café"};
    int ascii_order = std::strcmp(words[0], words[1]);
    // strcoll قد تُغيّر الترتيب حسب اللغة
    return ascii_order < 0 ? 1 : 0;
}

