    const char* text = "äbc";
    std::size_t len = std::strxfrm(transformed, text, sizeof(transformed));
    // الآن transformed يمكن مقارنتها بـ strcmp بدل strcoll
    return static_cast<int>(len);
}

#include <cstring>
